// Recoit les donnees du devis envoyees par le site et construit la
// soumission Docuseal a partir du MODELE reutilisable, en pre-remplissant
// les champs (numero, client, intervention, description, prix).
const body = $json.body || $json;

// >>>>>> REMPLACE 0 PAR L'ID DE TON MODELE DOCUSEAL <<<<<<
const TEMPLATE_ID = 0;

const n = (v) => Number(v || 0).toFixed(2);
const tva = Math.round((Number(body.devis_total_ttc) - Number(body.devis_total_ht)) * 100) / 100;

const client = [
  `${body.prenom || ''} ${body.nom || ''}`.trim(),
  body.societe || '',
  `Tel : ${body.telephone || ''}`,
  `Email : ${body.email || ''}`,
  body.adresse || '',
].filter(Boolean).join('\n');

const intervention = [
  body.date_formatee || '',
  `Creneau : ${body.heure || ''}`,
  `Surface : ${body.surface_m2 || ''} m2  -  ${body.type_toiture || ''}`,
  `Etat : ${body.etat_general || ''}`,
  `Acces : ${body.accessibilite || ''}`,
].filter(Boolean).join('\n');

const prix = [
  `Honoraires : ${n(body.devis_honoraires)} EUR`,
  `Deplacement (${body.devis_distance_km || 0} km) : ${n(body.devis_deplacement)} EUR`,
  `Total HT : ${n(body.devis_total_ht)} EUR`,
  `TVA 20% : ${tva.toFixed(2)} EUR`,
  `TOTAL TTC : ${n(body.devis_total_ttc)} EUR`,
].join('\n');

// Metadonnees transportees jusqu'au webhook form.completed (creation du RDV calendrier)
const metadata = {
  date: body.date || '',
  heure: body.heure || '',
  prenom: body.prenom || '',
  nom: body.nom || '',
  telephone: body.telephone || '',
  email: body.email || '',
  adresse: body.adresse || '',
  surface_m2: String(body.surface_m2 || ''),
  type_toiture: body.type_toiture || '',
  devis_total_ttc: String(body.devis_total_ttc || ''),
  devis_numero: body.devis_numero || '',
};

const submissionData = {
  template_id: TEMPLATE_ID,
  send_email: true,
  submitters: [
    {
      role: 'Client',
      name: `${body.prenom || ''} ${body.nom || ''}`.trim(),
      email: body.email,
      values: {
        numero: body.devis_numero || '',
        client,
        intervention,
        description: body.description || '',
        prix,
      },
      metadata,
    },
  ],
};

return [{ json: { submissionData } }];
